SELECT s.state_name, hd.observed_number
FROM states s
JOIN health_data hd ON s.state_id = hd.state_id;

SELECT week_ending, observed_number
FROM health_data
ORDER BY week_ending;

SELECT health_type_id, SUM(observed_number) AS total_observed_cases
FROM health_data
GROUP BY health_type_id;

SELECT total_observed
FROM data_summaries
WHERE year = 2020;
